public class Game {
    Room currentRoom;

    public void start() {
        currentRoom.describe();
    }

    public static void main(String[] args) {
        Game g = new Game();
        g.start();
    }
}

class Room {
    String name;
    public void describe() {
        System.out.println("You are in: " + name);
    }
}
